const PRIORITY = ['Recht','Treuhand','Immobilien','Handwerk','Beratung'];
const EXCLUDE = new Set(['Pilot Client','Paying Client']);

function getProp(p, key, type) {
  const v = p?.properties?.[key];
  if (!v) return '';
  if (type === 'title') return (v.title?.[0]?.plain_text) || '';
  if (type === 'rich_text') return (v.rich_text?.[0]?.plain_text) || '';
  if (type === 'select') return (v.select?.name) || '';
  if (type === 'status_or_select') return (v.status?.name) || (v.select?.name) || '';
  return '';
}

function urlencode(s) { return encodeURIComponent(s); }

const raw = items.map(i => i.json);
const leads = raw.map(p => ({
  name: getProp(p, 'Name', 'title'),
  firma: getProp(p, 'Firma', 'rich_text'),
  branche: getProp(p, 'Branche', 'select'),
  groesse: getProp(p, 'Größe', 'select'),
  top_problem: getProp(p, 'Top Problem', 'rich_text'),
  pipeline_stage: getProp(p, 'Pipeline Stage', 'status_or_select'),
})).filter(l => l.firma && l.name && !EXCLUDE.has(l.pipeline_stage));

leads.sort((a,b) => {
  const ra = PRIORITY.indexOf(a.branche); const rb = PRIORITY.indexOf(b.branche);
  const sa = ra === -1 ? PRIORITY.length : ra;
  const sb = rb === -1 ? PRIORITY.length : rb;
  if (sa !== sb) return sa - sb;
  const ta = a.top_problem.trim() ? 0 : 1;
  const tb = b.top_problem.trim() ? 0 : 1;
  if (ta !== tb) return ta - tb;
  return a.firma.toLowerCase().localeCompare(b.firma.toLowerCase());
});

const top = leads.slice(0, 20);
const lines = ['*Top ' + top.length + ' LinkedIn-Targets*\n'];
top.forEach((l, i) => {
  const url = 'https://www.linkedin.com/search/results/people/?keywords=' + urlencode('Inhaber ' + l.firma) + '&origin=SWITCH_SEARCH_VERTICAL';
  const branche = l.branche || '—';
  const problem = l.top_problem.length > 80 ? l.top_problem.slice(0,80) + '…' : l.top_problem;
  const pline = problem.trim() ? '\n  _' + problem + '_' : '';
  lines.push((i+1) + '. *' + l.firma + '* (' + branche + ') — [LinkedIn-Suche](' + url + ')' + pline);
});

return [{ json: { markdown: lines.join('\n'), count: top.length } }];

const m = $input.first().json.message;
let text = (m?.text || '').trim();
if (text.startsWith('/k ')) text = text.slice(3).trim();
else if (text === '/k') text = '';
if (!text || text.length < 30) {
  return [{ json: { __short: true, chat_id: m.chat.id } }];
}
return [{ json: { post_text: text, chat_id: m.chat.id, source: 'text' } }];

const item = $input.first();
const bin = item.binary?.data;
if (!bin) {
  return [{ json: { __error: 'no binary data' } }];
}
const chat_id = $('Telegram Trigger').item.json.message.chat.id;
return [{ json: { image_b64: bin.data, media_type: bin.mimeType || 'image/jpeg', chat_id, source: 'photo' } }];

const resp = $input.first().json;
const text = resp?.content?.[0]?.text || '';
const m = text.match(/\{[\s\S]*\}/);
if (!m) {
  throw new Error('No JSON found in Claude response: ' + text.slice(0, 200));
}
const parsed = JSON.parse(m[0]);

const chat_id = $('Build Anthropic Payload').item.json.chat_id;
const now = Date.now();

// Save state via $getWorkflowStaticData
const data = $getWorkflowStaticData('global');
// Cleanup entries older than 24h
for (const k in data) {
  if (data[k]?.ts && (now - data[k].ts) > 86_400_000) delete data[k];
}
// We don't yet know the message_id of the keyboard message — use chat_id + timestamp
const stateKey = chat_id + ':' + now;
data[stateKey] = {
  ts: now,
  summary: parsed.post_summary || '',
  branche: parsed.post_branche || 'Andere',
  variants: {
    Erfahrung: parsed.comments?.find(c => c.variant === 'Erfahrung')?.text || null,
    Sicht: parsed.comments?.find(c => c.variant === 'Sicht')?.text || null,
    Frage: parsed.comments?.find(c => c.variant === 'Frage')?.text || null
  }
};

function esc(s) {
  // MarkdownV2 escape
  return (s || '').replace(/([_*\[\]()~`>#+\-=|{}.!\\])/g, '\\$1');
}

const getVariant = (name) => parsed.comments?.find(c => c.variant === name) || {};

function format(label, idx, v) {
  if (!v.text) {
    return '⏭ *' + esc(label) + ' übersprungen* — _' + esc(v.skip_reason || 'kein passender Case') + '_';
  }
  return '*🟢 Variante ' + idx + ' — ' + esc(label) + '*\n\n```\n' + v.text + '\n```';
}

return [
  { json: { chat_id, msg: format('Erfahrung', 1, getVariant('Erfahrung')), stateKey, summary: parsed.post_summary, branche: parsed.post_branche } },
  { json: { chat_id, msg: format('Sicht', 2, getVariant('Sicht')), stateKey, summary: parsed.post_summary, branche: parsed.post_branche } },
  { json: { chat_id, msg: format('Frage', 3, getVariant('Frage')), stateKey, summary: parsed.post_summary, branche: parsed.post_branche } }
];

// Run after all 3 variants are sent. Build the keyboard message using state from first variant.
const all = $input.all();
const first = all[0].json;
const stateKey = first.stateKey;
const chat_id = first.chat_id;

const keyboard = {
  inline_keyboard: [
    [
      { text: '✅ Erfahrung', callback_data: 'log:Erfahrung:' + stateKey },
      { text: '✅ Sicht', callback_data: 'log:Sicht:' + stateKey }
    ],
    [
      { text: '✅ Frage', callback_data: 'log:Frage:' + stateKey },
      { text: '⏭ keine', callback_data: 'log:none:' + stateKey }
    ]
  ]
};

return [{ json: { chat_id, text: 'Welche hast du verwendet?', reply_markup: keyboard } }];

const cb = $input.first().json.callback_query;
if (!cb) throw new Error('No callback_query');
const data = cb.data || '';
const parts = data.split(':');
if (parts[0] !== 'log' || parts.length < 3) throw new Error('Bad callback_data: ' + data);
const variant = parts[1];
const stateKey = parts.slice(2).join(':');

const store = $getWorkflowStaticData('global');
const state = store[stateKey];

const chat_id = cb.message?.chat?.id;
const message_id = cb.message?.message_id;
const callback_query_id = cb.id;

if (!state) {
  return [{ json: {
    __no_state: true,
    chat_id, message_id, callback_query_id,
    answerText: 'State weg (älter als 24h)'
  } }];
}

const comment_text = (variant === 'none') ? '' : (state.variants?.[variant] || '');
const typ = 'Comment';
const notion_typ = (variant === 'none') ? 'keine' : variant;

return [{ json: {
  chat_id, message_id, callback_query_id,
  notion_typ,
  notion_branche: state.branche || 'Andere',
  notion_summary: state.summary || '',
  notion_comment: comment_text,
  notion_title: 'Comment · ' + new Date().toISOString().slice(0,10) + ' · ' + (state.summary || '').slice(0,60),
  answerText: variant === 'none' ? 'Notiert ✅' : 'Geloggt ✅'
} }];
